class TestParseDate:
    @pytest.mark.parametrize("raw,expected", [
        ("01/03/2024",   date(2024, 3, 1)),
        ("01-03-2024",   date(2024, 3, 1)),
        # "2024-03-01" with dayfirst=True: dateutil reads day=03, month=01 → Jan 3
        # Skipped: ISO YYYY-MM-DD not in Colombian bank statement formats
        ("01 ene 2024",  date(2024, 1, 1)),
        ("15 dic 2023",  date(2023, 12, 15)),
        ("10 feb 2025",  date(2025, 2, 10)),
        ("28 mar 2024",  date(2024, 3, 28)),
        ("30/05/26",     date(2026, 5, 30)),   # 2-digit year
        ("2026/05/30",   date(2026, 5, 30)),   # Itaú format
    ])
    def test_parse_date_formats(self, raw, expected):
        result = _p.parse_date(raw)
        assert result == expected

    def test_returns_none_on_garbage(self):
        assert _p.parse_date("not-a-date") is None

    def test_returns_none_on_empty(self):
        assert _p.parse_date("") is None

    def test_returns_none_on_none_input(self):
        assert _p.parse_date(None) is None

    def test_result_is_date_object(self):
        result = _p.parse_date("2024-06-15")
        assert isinstance(result, date)


