class TestDetectTransactionType:
    @pytest.mark.parametrize("indicator,amount,expected", [
        ("C",       100.0,  "credit"),
        ("D",      -100.0,  "debit"),
        ("CREDITO",  50.0,  "credit"),
        ("DEBITO",  -50.0,  "debit"),
        ("crédito",  50.0,  "credit"),
        ("débito",  -50.0,  "debit"),
        ("",        100.0,  "credit"),   # positive amount → credit
        ("",       -100.0,  "debit"),    # negative amount → debit
        ("",          0.0,  "debit"),    # zero → debit (safe default)
        ("ABONO",   500.0,  "credit"),
        ("COMPRA", -250.0,  "debit"),
    ])
    def test_detect_type(self, indicator, amount, expected):
        result = _p.detect_transaction_type(amount, indicator)
        assert result in ("debit", "credit")
        assert result == expected

    def test_returns_string(self):
        result = _p.detect_transaction_type(100.0, "C")
        assert isinstance(result, str)


