from tools.ingest.parsers.bogota_parser import BogotaParser

_bogota = BogotaParser()


class TestBogotaParserPureMethods:
    def test_get_bank_name(self):
        assert _bogota.get_bank_name() == "bogota"

    def test_find_header_detects_bogota_header(self):
        table = [
            ["Comprobante", "Descripción", "Valor Compra"],
            ["TXN001", "RAPPI DELIVERY", "45.000"],
        ]
        idx, col_map = _bogota._find_header(table)
        assert idx == 0
        assert col_map

    def test_find_header_returns_none_on_empty(self):
        idx, col_map = _bogota._find_header([])
        assert idx is None

    def test_build_col_map_maps_bogota_columns(self):
        header = ["Comprobante", "Descripción", "Valor Compra"]
        col_map = _bogota._build_col_map(header)
        # Returns dict with at minimum "desc" and "amount" keys
        assert isinstance(col_map, dict)

    def test_parse_data_row_returns_list(self):
        # Minimal test: method exists and returns a list
        col_map = {"date": 0, "description": 1, "debit": 2, "credit": 3}
        row = ["01/01/2024", "RAPPI DELIVERY", "45.000", ""]
        result = _bogota._parse_data_row(row, col_map)
        assert isinstance(result, list)

    def test_parse_table_with_valid_table(self):
        table = [
            ["Fecha", "Descripción", "Débito", "Crédito"],
            ["05/10/2025", "RAPPI*DELIVERY", "45.000", ""],
            ["10/10/2025", "NETFLIX.COM", "37.900", ""],
        ]
        results = _bogota._parse_table(table)
        assert isinstance(results, list)

    def test_parse_table_empty_returns_empty(self):
        assert _bogota._parse_table([]) == []

    def test_parse_table_header_only_returns_empty(self):
        table = [["Fecha", "Descripción", "Débito", "Crédito"]]
        result = _bogota._parse_table(table)
        assert isinstance(result, list)


